class Solution {
    public boolean canPartitionKSubsets(int[] nums, int k) {
        int sum = 0;
        for (int num : nums) {
            sum += num;
        }
        if (sum % k != 0) {
            return false;
        }
        int target = sum / k;
        boolean[] visited = new boolean[nums.length];
        return dfs(nums, new int[k], 0, target, visited);
    }

    private boolean dfs(int[] nums, int[] groups, int start, int target, boolean[] visited) {
        if (start == groups.length) {
            return true;
        }
        for (int i = 0; i < nums.length; i++) {
            if (!visited[i] && nums[i] <= target) {
                visited[i] = true;
                if (dfs(nums, groups, start, target - nums[i], visited)) {
                    return true;
                }
                visited[i] = false;
            }
        }
        return false;
    }
}
